    elevation: 0,
  },
  scrollView: {
    flex: 1,
    zIndex: 10,
    elevation: 10,
  },
  scrollContent: {
    paddingTop: 200, // Start scrolling after the header
  },
  overlayContainer: {
    paddingTop: 20,
    minHeight: 600,
    paddingBottom: 40,
    borderTopLeftRadius: 24,
    borderTopRightRadius: 24,
    shadowColor: "#000",
    shadowOffset: {
      width: 0,
      height: -2,
    },
    shadowOpacity: 0.1,
    shadowRadius: 3,
    elevation: 5,
  },
  welcomeGreeting: {
    fontSize: 18,
    fontWeight: '400',
    marginBottom: 8,
  },
  welcomeName: {
    fontSize: 36,
    fontWeight: '700',
    marginBottom: 8,
    textAlign: 'center',
  },
  dateText: {
    fontSize: 16,
    fontWeight: '500',
  },
  section: {
    marginBottom: 24,
    paddingHorizontal: 24,
  },
  sectionHeader: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 12,
  },
  sectionTitle: {
    fontSize: 22,
    fontWeight: '600',
    marginBottom: 12,
  },
  seeAllText: {
    fontSize: 14,
    fontWeight: '600',
  },
  card: {
    borderRadius: 16,
    padding: 20,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.06,
    shadowRadius: 8,
    elevation: 2,
  },
  attendanceMarked: {
    flexDirection: 'row',
    alignItems: 'center',
  },
  attendanceIconContainer: {
    width: 56,
    height: 56,
    borderRadius: 28,
    justifyContent: 'center',
    alignItems: 'center',
    marginRight: 16,
  },
  attendanceInfo: {
    flex: 1,
  },
  attendanceStatus: {
    fontSize: 17,
    fontWeight: '600',
  },
  attendanceTime: {
    fontSize: 14,
    marginTop: 4,
  },
  attendanceActions: {
    flexDirection: 'row',
    gap: 12,
  },
  attendanceButton: {
    flex: 1,
    flexDirection: 'row',
    padding: 14,
    borderRadius: 12,
    alignItems: 'center',
    justifyContent: 'center',
  },
  presentButton: {
    backgroundColor: '#00A699',
  },
  absentButton: {
    backgroundColor: '#FF5A5F',
  },
  buttonIcon: {
    marginRight: 8,
  },
  attendanceButtonText: {
    color: '#FFFFFF',
    fontWeight: '600',
    fontSize: 15,
  },
  classHeader: {
    flexDirection: 'row',
    alignItems: 'center',
    marginBottom: 16,
  },
  classIconContainer: {
    width: 56,
    height: 56,
    borderRadius: 16,
    backgroundColor: '#FFF0F5',
    justifyContent: 'center',
    alignItems: 'center',
    marginRight: 16,
  },
  classInfo: {
    flex: 1,
  },
  className: {
    fontSize: 18,
    fontWeight: '600',
  },
  classSection: {
    fontSize: 15,
    marginTop: 2,
  },
  classActions: {
    flexDirection: 'row',
    gap: 12,
  },
  classButton: {
    flex: 1,
    padding: 14,
    borderRadius: 12,
    alignItems: 'center',
  },
  classButtonPrimary: {
    backgroundColor: '#E31C5F',
  },
  classButtonText: {
    fontWeight: '600',
    fontSize: 15,
  },
  classButtonTextPrimary: {
    color: '#FFFFFF',
    fontWeight: '600',
    fontSize: 15,
  },
  periodItem: {
    flexDirection: 'row',
    alignItems: 'center',
    paddingVertical: 12,
  },
  periodItemBorder: {
    borderBottomWidth: 1,
