import React from 'react';
import { StyleSheet } from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { format } from 'date-fns';

export default function DashboardHeader({ teacherName }: { teacherName: string }) {
  return (
    <LinearGradient
      colors={['#FF3CAC', '#784BA0', '#2B86C5']}
      start={{ x: 0, y: 0 }}
      end={{ x: 1, y: 1 }}
      style={styles.fixedHeader}
    >
      <Text style={[styles.welcomeGreeting, { color: '#FFFFFF' }]}>Good {getGreeting()},</Text>
      <Text style={[styles.welcomeName, { color: '#FFFFFF' }]}>{teacherName}</Text>
      <Text style={[styles.dateText, { color: '#FFFFFFCC' }]}>
        {format(new Date(), 'EEEE, MMMM d')}
      </Text>
    </LinearGradient>
  );
}

function getGreeting() {
  const hour = new Date().getHours();
  if (hour < 12) return 'morning';
  if (hour < 17) return 'afternoon';
  return 'evening';
}

const styles = StyleSheet.create({
  fixedHeader: {
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    height: 230,
    justifyContent: 'center',
    alignItems: 'center',
    paddingTop: 40,
    zIndex: 0,
    elevation: 0,
  },
  welcomeGreeting: {
    fontSize: 18,
    fontWeight: '400',
    marginBottom: 8,
  },
  welcomeName: {
    fontSize: 36,
    fontWeight: '700',
    marginBottom: 8,
    textAlign: 'center',
  },
  dateText: {
    fontSize: 16,
    fontWeight: '500',
  },
});

