   514→        {/* Guided Tour Overlay */}
   515→        <GuidedTour
   516→          visible={tour.visible}
   517→          steps={DEFAULT_TOUR_STEPS}
   518→          currentStepIndex={tour.currentStepIndex}
   519→          onClose={tour.close}
   520→          onNext={tour.onNext}
