     1→import React, { useEffect, useState, useCallback, useRef } from 'react';
     2→import { LinearGradient } from 'expo-linear-gradient';
     3→import {
     4→  View,
     5→  Text,
     6→  ScrollView,
     7→  StyleSheet,
     8→  TouchableOpacity,
     9→  ActivityIndicator,
    10→  RefreshControl,
    11→  Alert,
    12→  SafeAreaView,
    13→  Platform,
    14→  StatusBar,
    15→} from 'react-native';
    16→import { useRouter, useSegments } from 'expo-router';
    17→import { useAuth } from '../../context/AuthContext';
    18→import api from '../../services/api';
    19→import { format } from 'date-fns';
    20→import { Ionicons } from '@expo/vector-icons';
    21→import { GuidedTour, DEFAULT_TOUR_STEPS } from '../../components';
    22→import { useGuidedTour } from '../../hooks';
    23→import { useTheme } from '../../context/ThemeContext';
    24→
    25→interface DashboardData {
    26→  teacher: {
    27→    id: string;
    28→    name: string;
    29→    photo?: string;
    30→  };
    31→  classTeacher: {
    32→    name: string;
    33→    section: string;
    34→  } | null;
    35→  attendance: {
    36→    status: string | null;
    37→    inTime: string | null;
    38→  };
    39→  timetable: any[];
    40→  substitutions: any[];
    41→  gatePasses: any[];
    42→  appointments: any[];
    43→  unreadAnnouncements: number;
    44→}
    45→
    46→export default function DashboardScreen() {
    47→  const { user, isLoading: authLoading } = useAuth();
    48→  const { colors } = useTheme();
    49→  const router = useRouter();
    50→  const segments = useSegments();
    51→  const [data, setData] = useState<DashboardData | null>(null);
    52→  const [loading, setLoading] = useState(true);
    53→  const [refreshing, setRefreshing] = useState(false);
    54→  const [debugInfo, setDebugInfo] = useState<string>('');
    55→
    56→  // Track if dashboard has been loaded for current user to prevent duplicate calls
    57→  const hasLoadedRef = useRef(false);
    58→  const isLoadingRef = useRef(false);
    59→
    60→  // Guided tour
    61→  const tour = useGuidedTour({
    62→    steps: DEFAULT_TOUR_STEPS,
    63→    onComplete: () => {
    64→      // Return to dashboard after tour completes
    65→      router.replace('/(tabs)');
    66→    },
    67→  });
    68→
    69→  const loadDashboard = useCallback(async () => {
    70→    // Prevent concurrent requests
    71→    if (isLoadingRef.current) {
    72→      console.log('Dashboard load already in progress, skipping');
    73→      return;
    74→    }
    75→
    76→    if (!user?.id) {
    77→      console.log('No user ID available');
    78→      setDebugInfo('No user ID available');
    79→      setLoading(false);
    80→      setRefreshing(false);
    81→      return;
    82→    }
    83→
    84→    // Prevent duplicate loads for same user
    85→    if (hasLoadedRef.current && !refreshing) {
    86→      console.log('Dashboard already loaded for user:', user.id);
    87→      return;
    88→    }
    89→
    90→    isLoadingRef.current = true;
    91→    console.log('Loading dashboard for user:', user.id);
    92→    setDebugInfo(`Loading dashboard for user: ${user.id}`);
    93→
    94→    try {
    95→      const dashboardData = await api.getDashboardData(user.id);
    96→      console.log('Dashboard data loaded successfully');
    97→      setDebugInfo('Dashboard data loaded successfully');
    98→      setData(dashboardData);
    99→      hasLoadedRef.current = true;
   100→    } catch (error) {
   101→      console.error('Error loading dashboard:', error);
   102→      const errorMsg = error instanceof Error ? error.message : 'Unknown error';
   103→      setDebugInfo(`Error: ${errorMsg}`);
   104→
   105→      // Show more helpful error message based on error type
   106→      if (error instanceof Error && error.name === 'AbortError') {
   107→        Alert.alert(
   108→          'Connection Timeout',
   109→          'The server is taking too long to respond. Please check your network connection and try again.',
   110→          [
   111→            { text: 'Cancel', style: 'cancel' },
   112→            {
   113→              text: 'Retry', onPress: () => {
   114→                hasLoadedRef.current = false;
   115→                loadDashboard();
   116→              }
   117→            }
   118→          ]
   119→        );
   120→      } else {
   121→        Alert.alert(
   122→          'Error',
   123→          'Failed to load dashboard data. Please try again.',
   124→          [
   125→            { text: 'Cancel', style: 'cancel' },
   126→            {
   127→              text: 'Retry', onPress: () => {
   128→                hasLoadedRef.current = false;
   129→                loadDashboard();
   130→              }
   131→            }
   132→          ]
   133→        );
   134→      }
   135→    } finally {
   136→      setLoading(false);
   137→      setRefreshing(false);
   138→      isLoadingRef.current = false;
   139→    }
   140→  }, [user?.id, refreshing]);
   141→
   142→  // Load dashboard when user changes, but prevent duplicate loads
   143→  useEffect(() => {
   144→    // Reset loaded state when user changes
   145→    if (user?.id) {
   146→      hasLoadedRef.current = false;
   147→    }
   148→    loadDashboard();
   149→  }, [user?.id]); // Only depend on user.id, not loadDashboard function
   150→
   151→  // Debug logging - console only, no state updates to prevent re-renders
   152→  useEffect(() => {
   153→    const state = {
   154→      authLoading,
   155→      loading,
   156→      hasUser: !!user,
   157→      userId: user?.id,
   158→      hasData: !!data
   159→    };
   160→    console.log('Dashboard state:', state);
   161→    // Note: Removed setDebugInfo to prevent infinite re-render loop
   162→  }, [authLoading, loading, user, data]);
   163→
   164→  // Start tour when dashboard is first loaded
   165→  useEffect(() => {
   166→    // Wait for navigation to be ready and screen to render
   167→    if (!loading && !authLoading && data) {
   168→      const timer = setTimeout(() => {
   169→        tour.start();
   170→      }, 1000);
   171→      return () => clearTimeout(timer);
   172→    }
   173→  }, [loading, authLoading, data]);
   174→
   175→  const onRefresh = useCallback(() => {
   176→    hasLoadedRef.current = false; // Allow reload
   177→    setRefreshing(true);
   178→    loadDashboard();
   179→  }, [loadDashboard]);
   180→
   181→  const markAttendance = useCallback(async (status: string) => {
   182→    if (!user?.id) return;
   183→    try {
   184→      await api.markTeacherAttendance(user.id, {
   185→        status,
   186→        inTime: status === 'present' ? format(new Date(), 'HH:mm') : undefined,
   187→      });
   188→      hasLoadedRef.current = false; // Allow reload
   189→      loadDashboard();
   190→    } catch (error) {
   191→      console.error('Error marking attendance:', error);
   192→      Alert.alert('Error', 'Failed to mark attendance. Please try again.');
   193→    }
   194→  }, [user?.id, loadDashboard]);
   195→
   196→  const resetAttendance = useCallback(async () => {
   197→    if (!user?.id) return;
   198→    try {
   199→      await api.resetTeacherAttendance(user.id);
   200→      hasLoadedRef.current = false; // Allow reload
   201→      loadDashboard();
   202→    } catch (error) {
   203→      console.error('Error resetting attendance:', error);
   204→      Alert.alert('Error', 'Failed to reset attendance. Please try again.');
   205→    }
   206→  }, [user?.id, loadDashboard]);
   207→
   208→  if (authLoading || loading) {
   209→    return (
   210→      <SafeAreaView style={styles.centerContainer}>
   211→        <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
   212→        <ActivityIndicator size="large" color={colors.primary} />
   213→        <Text style={{ marginTop: 16, color: colors.textSecondary, fontSize: 16 }}>
   214→          {authLoading ? 'Checking authentication...' : 'Loading dashboard...'}
   215→        </Text>
   216→        <View style={{ marginTop: 20, padding: 16, backgroundColor: '#f0f0f0', borderRadius: 8, maxWidth: '80%' }}>
   217→          <Text style={{ fontSize: 12, fontFamily: 'monospace', color: colors.text }}>
   218→            {debugInfo || 'Initializing...'}
   219→          </Text>
   220→        </View>
   221→      </SafeAreaView>
   222→    );
   223→  }
   224→
   225→  if (!user) {
   226→    return (
   227→      <SafeAreaView style={styles.centerContainer}>
   228→        <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
   229→        <Ionicons name="person-outline" size={48} color={colors.border} />
   230→        <Text style={styles.emptyText}>No user logged in</Text>
   231→        <TouchableOpacity
   232→          style={[styles.attendanceButton, styles.presentButton, { marginTop: 16 }]}
   233→          onPress={() => router.replace('/login')}
   234→          accessibilityRole="button"
   235→          accessibilityLabel="Go to Login"
   236→        >
   237→          <Text style={styles.attendanceButtonText}>Go to Login</Text>
   238→        </TouchableOpacity>
   239→      </SafeAreaView>
   240→    );
   241→  }
   242→
   243→  if (!data) {
   244→    return (
   245→      <SafeAreaView style={styles.centerContainer}>
   246→        <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
   247→        <Ionicons name="alert-circle-outline" size={48} color={colors.border} />
   248→        <Text style={styles.emptyText}>No data available</Text>
   249→        <TouchableOpacity
   250→          style={[styles.attendanceButton, styles.presentButton, { marginTop: 16 }]}
   251→          onPress={loadDashboard}
   252→          accessibilityRole="button"
   253→          accessibilityLabel="Retry loading dashboard"
   254→        >
   255→          <Text style={styles.attendanceButtonText}>Retry</Text>
   256→        </TouchableOpacity>
   257→      </SafeAreaView>
   258→    );
   259→  }
   260→
   261→  return (
   262→    <SafeAreaView style={[styles.mainContainer, { backgroundColor: colors.background }]}>
   263→      <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
   264→      {/* Fixed Header Section */}
   265→      <LinearGradient
   266→        colors={['#FF3CAC', '#784BA0', '#2B86C5']}
   267→        start={{ x: 0, y: 0 }}
   268→        end={{ x: 1, y: 1 }}
   269→        style={styles.fixedHeader}
   270→      >
   271→        <Text style={[styles.welcomeGreeting, { color: '#FFFFFF' }]}>Good {getGreeting()},</Text>
   272→        <Text style={[styles.welcomeName, { color: '#FFFFFF' }]}>{data.teacher.name}</Text>
   273→        <Text style={[styles.dateText, { color: '#FFFFFFCC' }]}>{format(new Date(), 'EEEE, MMMM d')}</Text>
   274→      </LinearGradient>
   275→
   276→      <ScrollView
   277→        style={styles.scrollView}
   278→        contentContainerStyle={styles.scrollContent}
   279→        showsVerticalScrollIndicator={false}
   280→        refreshControl={
   281→          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={colors.primary} />
   282→        }
   283→      >
   284→        <View style={[styles.overlayContainer, { backgroundColor: colors.background }]}>
   285→          {/* Attendance Card */}
   286→          <View style={styles.section}>
   287→            <Text style={[styles.sectionTitle, { color: colors.text }]}>Today's Attendance</Text>
   288→            <View style={[styles.card, { backgroundColor: colors.card }]}>
   289→              {data.attendance.status ? (
   290→                <>
   291→                  <View style={styles.attendanceMarked}>
   292→                    <View style={styles.attendanceIconContainer}>
   293→                      <Ionicons
   294→                        name={data.attendance.status === 'present' ? 'checkmark-circle' : 'close-circle'}
   295→                        size={32}
   296→                        color={data.attendance.status === 'present' ? colors.success : colors.error}
   297→                      />
   298→                    </View>
   299→                    <View style={styles.attendanceInfo}>
   300→                      <Text style={[styles.attendanceStatus, { color: colors.text }]}>
   301→                        Marked as {data.attendance.status.charAt(0).toUpperCase() + data.attendance.status.slice(1)}
   302→                      </Text>
   303→                      {data.attendance.inTime && (
   304→                        <Text style={[styles.attendanceTime, { color: colors.textSecondary }]}>Check-in: {data.attendance.inTime}</Text>
   305→                      )}
   306→                    </View>
   307→                  </View>
   308→                  <TouchableOpacity
   309→                    style={[styles.resetButton]}
   310→                    onPress={resetAttendance}
   311→                    accessibilityRole="button"
   312→                    accessibilityLabel="Reset Attendance"
   313→                  >
   314→                    <Ionicons name="refresh-outline" size={16} color={colors.textSecondary} style={styles.resetButtonIcon} />
   315→                    <Text style={styles.resetButtonText}>Reset Attendance</Text>
   316→                  </TouchableOpacity>
   317→                </>
   318→              ) : (
   319→                <View style={styles.attendanceActions}>
   320→                  <TouchableOpacity
   321→                    style={[styles.attendanceButton, styles.presentButton]}
   322→                    onPress={() => markAttendance('present')}
   323→                    accessibilityRole="button"
   324→                    accessibilityLabel="Mark Present"
   325→                  >
   326→                    <Ionicons name="checkmark" size={18} color={colors.white} style={styles.buttonIcon} />
   327→                    <Text style={styles.attendanceButtonText}>Mark Present</Text>
   328→                  </TouchableOpacity>
   329→                  <TouchableOpacity
   330→                    style={[styles.attendanceButton, styles.absentButton]}
   331→                    onPress={() => markAttendance('absent')}
   332→                    accessibilityRole="button"
   333→                    accessibilityLabel="Mark Absent"
   334→                  >
   335→                    <Ionicons name="close" size={18} color={colors.white} style={styles.buttonIcon} />
   336→                    <Text style={styles.attendanceButtonText}>Mark Absent</Text>
   337→                  </TouchableOpacity>
   338→                </View>
   339→              )}
   340→            </View>
   341→          </View>
   342→
   343→          {/* Class Teacher Section */}
   344→          {data.classTeacher && (
   345→            <View style={styles.section}>
   346→              <Text style={[styles.sectionTitle, { color: colors.text }]}>My Class</Text>
   347→              <View style={[styles.card, { backgroundColor: colors.card }]}>
   348→                <View style={styles.classHeader}>
   349→                  <View style={styles.classIconContainer}>
   350→                    <Ionicons name="school" size={28} color={colors.primary} />
   351→                  </View>
   352→                  <View style={styles.classInfo}>
   353→                    <Text style={[styles.className, { color: colors.text }]}>{data.classTeacher.name}</Text>
   354→                    <Text style={[styles.classSection, { color: colors.textSecondary }]}>Section {data.classTeacher.section}</Text>
   355→                  </View>
   356→                </View>
   357→                <View style={styles.classActions}>
   358→                  <TouchableOpacity
   359→                    style={[styles.classButton, { backgroundColor: colors.backgroundGray }]}
   360→                    onPress={() => router.push('/class-details')}
   361→                    accessibilityRole="button"
   362→                    accessibilityLabel="View Class"
   363→                  >
   364→                    <Text style={[styles.classButtonText, { color: colors.text }]}>View Class</Text>
   365→                  </TouchableOpacity>
   366→                  <TouchableOpacity
   367→                    style={[styles.classButton, styles.classButtonPrimary]}
   368→                    onPress={() => router.push('/attendance')}
   369→                    accessibilityRole="button"
   370→                    accessibilityLabel="Take Attendance"
   371→                  >
   372→                    <Text style={styles.classButtonTextPrimary}>Take Attendance</Text>
   373→                  </TouchableOpacity>
   374→                </View>
   375→              </View>
   376→            </View>
   377→          )}
   378→
   379→          {/* Today's Schedule */}
