   381→            <View style={styles.sectionHeader}>
   382→              <Text style={[styles.sectionTitle, { color: colors.text }]}>Today's Schedule</Text>
   383→              <TouchableOpacity
   384→                onPress={() => router.push('/(tabs)/timetable')}
   385→                accessibilityRole="button"
   386→                accessibilityLabel="See all timetable"
   387→              >
   388→                <Text style={[styles.seeAllText, { color: colors.primary }]}>See all</Text>
   389→              </TouchableOpacity>
   390→            </View>
   391→            <View style={[styles.card, { backgroundColor: colors.card }]}>
