   393→                data.timetable.map((period, index) => (
   394→                  <View key={index} style={[styles.periodItem, index < data.timetable.length - 1 && styles.periodItemBorder]}>
   395→                    <View style={[styles.periodNumber, { backgroundColor: colors.backgroundGray }]}>
