import React from 'react';
import { View, Text, StyleSheet, TouchableOpacity } from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { useTheme } from '../../../context/ThemeContext';
import { useRouter } from 'expo-router';

export default function QuickActionsGrid() {
  const { colors } = useTheme();
  const router = useRouter();

  const quickActions = [
    {
      id: 'homework',
      icon: 'create-outline',
      label: 'Create\nHomework',
      bgColor: colors.primary + '15',
      iconColor: colors.primary,
      route: '/homework',
      params: { action: 'create' },
    },
    {
      id: 'leave',
      icon: 'time-outline',
      label: 'Apply\nLeave',
      bgColor: colors.success + '15',
      iconColor: colors.success,
      route: '/(tabs)/profile',
    },
    {
      id: 'message',
      icon: 'chatbubble-outline',
      label: 'Send\nMessage',
      bgColor: '#F5A623' + '15',
      iconColor: '#F5A623',
      route: '/chat',
    },
    {
      id: 'payslip',
      icon: 'receipt-outline',
      label: 'View\nPayslip',
      bgColor: '#6B5B95' + '15',
      iconColor: '#6B5B95',
      route: '/payslips',
    },
  ];

  return (
    <View style={styles.section}>
      <Text style={[styles.sectionTitle, { color: colors.text }]}>Quick Actions</Text>
      <View style={styles.quickActionsGrid}>
        {quickActions.map((action) => (
          <TouchableOpacity
            key={action.id}
            style={[styles.quickActionCard, { backgroundColor: colors.card }]}
            onPress={() => router.push({ pathname: action.route, params: action.params })}
          >
            <View style={[styles.quickActionIcon, { backgroundColor: action.bgColor }]}>
              <Ionicons name={action.icon as any} size={24} color={action.iconColor} />
            </View>
            <Text style={[styles.quickActionText, { color: colors.text }]}>{action.label}</Text>
          </TouchableOpacity>
        ))}
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  section: {
    marginBottom: 24,
    paddingHorizontal: 24,
  },
  sectionTitle: {
    fontSize: 22,
    fontWeight: '600',
    marginBottom: 12,
  },
  quickActionsGrid: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: 12,
  },
  quickActionCard: {
    width: '23%',
    aspectRatio: 1,
    borderRadius: 16,
    padding: 12,
    alignItems: 'center',
    justifyContent: 'center',
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.06,
    shadowRadius: 8,
    elevation: 2,
  },
  quickActionIcon: {
    width: 44,
    height: 44,
    borderRadius: 12,
    justifyContent: 'center',
    alignItems: 'center',
    marginBottom: 8,
  },
  quickActionText: {
    fontWeight: '500',
    fontSize: 11,
    textAlign: 'center',
    lineHeight: 14,
  },
});

