import React from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  Alert,
} from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { useTheme } from '../../../context/ThemeContext';

interface AttendanceData {
  status: string | null;
  inTime: string | null;
}

interface AttendanceCardProps {
  attendance: AttendanceData;
  onMarkPresent: () => void;
  onMarkAbsent: () => void;
  onReset: () => void;
}

export default function AttendanceCard({
  attendance,
  onMarkPresent,
  onMarkAbsent,
  onReset,
}: AttendanceCardProps) {
  const { colors } = useTheme();

  return (
    <View style={styles.section}>
      <Text style={[styles.sectionTitle, { color: colors.text }]}>Today's Attendance</Text>
      <View style={[styles.card, { backgroundColor: colors.card }]}>
        {attendance.status ? (
          <>
            <View style={styles.attendanceMarked}>
              <View style={styles.attendanceIconContainer}>
                <Ionicons
                  name={attendance.status === 'present' ? 'checkmark-circle' : 'close-circle'}
                  size={32}
                  color={attendance.status === 'present' ? colors.success : colors.error}
                />
              </View>
              <View style={styles.attendanceInfo}>
                <Text style={[styles.attendanceStatus, { color: colors.text }]}>
                  Marked as {attendance.status.charAt(0).toUpperCase() + attendance.status.slice(1)}
                </Text>
                {attendance.inTime && (
                  <Text style={[styles.attendanceTime, { color: colors.textSecondary }]}>
                    Check-in: {attendance.inTime}
                  </Text>
                )}
              </View>
            </View>
            <TouchableOpacity
              style={[styles.resetButton]}
              onPress={onReset}
            >
              <Ionicons name="refresh-outline" size={16} color={colors.textSecondary} style={styles.resetButtonIcon} />
              <Text style={styles.resetButtonText}>Reset Attendance</Text>
            </TouchableOpacity>
          </>
        ) : (
          <View style={styles.attendanceActions}>
            <TouchableOpacity
              style={[styles.attendanceButton, styles.presentButton]}
              onPress={onMarkPresent}
            >
              <Ionicons name="checkmark" size={18} color={colors.white} style={styles.buttonIcon} />
              <Text style={styles.attendanceButtonText}>Mark Present</Text>
            </TouchableOpacity>
            <TouchableOpacity
              style={[styles.attendanceButton, styles.absentButton]}
              onPress={onMarkAbsent}
            >
              <Ionicons name="close" size={18} color={colors.white} style={styles.buttonIcon} />
              <Text style={styles.attendanceButtonText}>Mark Absent</Text>
            </TouchableOpacity>
          </View>
        )}
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  section: {
    marginBottom: 24,
    paddingHorizontal: 24,
  },
  sectionTitle: {
    fontSize: 22,
    fontWeight: '600',
    marginBottom: 12,
  },
