    borderRadius: 16,
    padding: 20,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.06,
    shadowRadius: 8,
    elevation: 2,
  },
  attendanceMarked: {
    flexDirection: 'row',
    alignItems: 'center',
  },
  attendanceIconContainer: {
    width: 56,
    height: 56,
    borderRadius: 28,
    justifyContent: 'center',
    alignItems: 'center',
    marginRight: 16,
  },
  attendanceInfo: {
    flex: 1,
  },
  attendanceStatus: {
    fontSize: 17,
    fontWeight: '600',
  },
  attendanceTime: {
    fontSize: 14,
    marginTop: 4,
  },
  attendanceActions: {
    flexDirection: 'row',
    gap: 12,
  },
  attendanceButton: {
    flex: 1,
    flexDirection: 'row',
    padding: 14,
    borderRadius: 12,
    alignItems: 'center',
    justifyContent: 'center',
  },
