import React from 'react';
import { View, Text, StyleSheet, TouchableOpacity } from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { useTheme } from '../../../context/ThemeContext';
import { useRouter } from 'expo-router';

interface ClassTeacherData {
  name: string;
  section: string;
}

interface ClassTeacherCardProps {
  classTeacher: ClassTeacherData;
}

export default function ClassTeacherCard({ classTeacher }: ClassTeacherCardProps) {
  const { colors } = useTheme();
  const router = useRouter();

  return (
    <View style={styles.section}>
      <Text style={[styles.sectionTitle, { color: colors.text }]}>My Class</Text>
      <View style={[styles.card, { backgroundColor: colors.card }]}>
        <View style={styles.classHeader}>
          <View style={[styles.classIconContainer, { backgroundColor: colors.primaryLight || colors.primary + '15' }]}>
            <Ionicons name="school" size={28} color={colors.primary} />
          </View>
          <View style={styles.classInfo}>
            <Text style={[styles.className, { color: colors.text }]}>{classTeacher.name}</Text>
            <Text style={[styles.classSection, { color: colors.textSecondary }]}>
              Section {classTeacher.section}
            </Text>
          </View>
        </View>
        <View style={styles.classActions}>
          <TouchableOpacity
            style={[styles.classButton, { backgroundColor: colors.backgroundGray }]}
            onPress={() => router.push('/class-details')}
          >
            <Text style={[styles.classButtonText, { color: colors.text }]}>View Class</Text>
          </TouchableOpacity>
          <TouchableOpacity
            style={[styles.classButton, { backgroundColor: colors.error }]}
            onPress={() => router.push('/attendance')}
          >
            <Text style={[styles.classButtonTextPrimary, { color: colors.white }]}>Take Attendance</Text>
          </TouchableOpacity>
        </View>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  section: {
    marginBottom: 24,
    paddingHorizontal: 24,
  },
  sectionTitle: {
    fontSize: 22,
    fontWeight: '600',
    marginBottom: 12,
