    elevation: 2,
  },
  classHeader: {
    flexDirection: 'row',
    alignItems: 'center',
    marginBottom: 16,
  },
  classIconContainer: {
    width: 56,
    height: 56,
    borderRadius: 16,
    backgroundColor: '#FFF0F5',
    justifyContent: 'center',
    alignItems: 'center',
    marginRight: 16,
  },
  classInfo: {
    flex: 1,
  },
  className: {
    fontSize: 18,
    fontWeight: '600',
  },
  classSection: {
    fontSize: 15,
    marginTop: 2,
  },
  classActions: {
    flexDirection: 'row',
    gap: 12,
  },
  classButton: {
    flex: 1,
    padding: 14,
    borderRadius: 12,
    alignItems: 'center',
  },
  classButtonPrimary: {
    backgroundColor: '#E31C5F',
  },
  classButtonText: {
    fontWeight: '600',
    fontSize: 15,
  },
