  },
  presentButton: (colors: any) => ({
    backgroundColor: colors.success,
  }),
  absentButton: (colors: any) => ({
    backgroundColor: colors.error,
  }),
  buttonIcon: {
    marginRight: 8,
  },
  attendanceButtonText: (colors: any) => ({
    color: colors.white,
    fontWeight: '600',
    fontSize: 15,
  }),
  classHeader: {
    flexDirection: 'row',
