    fontSize: 15,
    marginTop: 2,
  },
  classActions: {
    flexDirection: 'row',
    gap: 12,
  },
  classButton: {
    flex: 1,
    padding: 14,
    borderRadius: 12,
    alignItems: 'center',
  },
  classButtonPrimary: {
    backgroundColor: '#E31C5F',
  },
  classButtonText: {
    fontWeight: '600',
    fontSize: 15,
  },
  classButtonTextPrimary: {
    color: '#FFFFFF',
    fontWeight: '600',
    fontSize: 15,
